 {\\n      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;\\n      setThemeState(prefersDark ? 'dark' : 'light');\\n    }\\n  }, []);\\n\\n  useEffect(() => {\\n    if (!mounted) return;\\n    localStorage.setItem(THEME_STORAGE_KEY, theme);\\n    if (theme === 'dark') {\\n      document.body.classList.add('bp5-dark');\\n    } else {\\n      document.body.classList.remove('bp5-dark');\\n    }\\n  }, [theme, mounted]);\\n\\n  const toggleTheme = useCallback(() => {\\n    setThemeState(t => t === 'light' ? 'dark' : 'light');\\n  }, []);\\n\\n  const setTheme = useCallback((newTheme: Theme) => {\\n    setThemeState(newTheme);\\n  }, []);\\n\\n  if (!mounted) return null;\\n\\n  return (\\n    <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>\\n      {children}\\n    </ThemeContext.Provider>\\n  );\\n}\\n\\nexport function useTheme(): ThemeContextType {\\n  const context = useContext(ThemeContext);\\n  if (!context) throw new Error('useTheme must be used within a ThemeProvider');\\n  return context;\\n}\", \"user_feedback\": \"ThemeContext working - toggles bp5-dark class correctly, persists to localStorage\", \"context\": \"Theme management using Blueprint.js bp5-dark class for dark mode\", \"source_line\": 1019}\n{\"task_id\": \"TASK-040\", \"code_type\": \"config\", \"file_name\": \"features.json\", \"code\": \"{\\n  \\\"01-common\\\": [{\\\"id\\\": \\\"MetricBadge\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"LegendItem\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"SectionTitle\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"TabBar\\\", \\\"status\\\": \\\"pending\\\"}],\\n  \\\"02-layout\\\": [{\\\"id\\\": \\\"AppHeader\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"TimeScrubber\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"ViewPanel\\\", \\\"status\\\": \\\"pending\\\"}, {\\\"id\\\": \\\"SimulationSidebar\\\", \\\"status\\\": \\\"pending\\\"}],\\n  \\\"03-controls\\\": [{\\